#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <sys/time.h>

#define fp double

#define NUMBER_PAR_PER_BOX 100

#ifdef RD_WG_SIZE_0_0
    #define NUMBER_THREADS RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
    #define NUMBER_THREADS RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
    #define NUMBER_THREADS RD_WG_SIZE
#else
    #define NUMBER_THREADS 128
#endif

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
    fp x, y, z;
} THREE_VECTOR;

typedef struct
{
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str
{
    int x, y, z;
    int number;
    long offset;

    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str
{
    fp alpha;
} par_str;

typedef struct dim_str
{
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;

    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

#if defined(__GNUC__)
extern "C" int device_id_inuse __attribute__((weak));
#endif

static inline void fatal_cuda(cudaError_t err, int line_no)
{
    if (err != cudaSuccess) {
        printf("Cuda error at line %d: %s\n", line_no, cudaGetErrorString(err));
        fflush(NULL);
        exit(EXIT_FAILURE);
    }
}

#define CUDA_CHECK(call) fatal_cuda((call), __LINE__)

static inline float elapsed_ms(const struct timeval* start, const struct timeval* end)
{
    return (float)((end->tv_sec - start->tv_sec) * 1000.0 +
                   (end->tv_usec - start->tv_usec) / 1000.0);
}

__global__ void kernel_gpu_cuda(par_str d_par_gpu,
                                dim_str d_dim_gpu,
                                const box_str* d_box_gpu,
                                const FOUR_VECTOR* d_rv_gpu,
                                const fp* d_qv_gpu,
                                FOUR_VECTOR* d_fv_gpu)
{
    int bx = blockIdx.x;
    int tx = threadIdx.x;
    int wtx = tx;

    __shared__ FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
    __shared__ FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
    __shared__ fp qB_shared[NUMBER_PAR_PER_BOX];

    if (bx < d_dim_gpu.number_boxes) {

        fp a2 = (fp)2.0 * d_par_gpu.alpha * d_par_gpu.alpha;

        long first_i = d_box_gpu[bx].offset;

        while (wtx < NUMBER_PAR_PER_BOX) {
            rA_shared[wtx] = d_rv_gpu[first_i + wtx];
            wtx = wtx + NUMBER_THREADS;
        }
        wtx = tx;

        __syncthreads();

        for (int k = 0; k < (1 + d_box_gpu[bx].nn); k++) {

            int pointer;
            if (k == 0) {
                pointer = bx;
            } else {
                pointer = d_box_gpu[bx].nei[k - 1].number;
            }

            long first_j = d_box_gpu[pointer].offset;

            while (wtx < NUMBER_PAR_PER_BOX) {
                rB_shared[wtx] = d_rv_gpu[first_j + wtx];
                qB_shared[wtx] = d_qv_gpu[first_j + wtx];
                wtx = wtx + NUMBER_THREADS;
            }
            wtx = tx;

            __syncthreads();

            while (wtx < NUMBER_PAR_PER_BOX) {

                FOUR_VECTOR f = d_fv_gpu[first_i + wtx];
                FOUR_VECTOR rA = rA_shared[wtx];

                for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                    fp r2 = rA.v + rB_shared[j].v - DOT(rA, rB_shared[j]);
                    fp u2 = a2 * r2;
                    fp vij = exp(-u2);
                    fp fs = (fp)2.0 * vij;

                    THREE_VECTOR d;
                    d.x = rA.x - rB_shared[j].x;
                    fp fxij = fs * d.x;
                    d.y = rA.y - rB_shared[j].y;
                    fp fyij = fs * d.y;
                    d.z = rA.z - rB_shared[j].z;
                    fp fzij = fs * d.z;

                    fp q = qB_shared[j];
                    f.v += q * vij;
                    f.x += q * fxij;
                    f.y += q * fyij;
                    f.z += q * fzij;
                }

                d_fv_gpu[first_i + wtx] = f;
                wtx = wtx + NUMBER_THREADS;
            }

            wtx = tx;

            __syncthreads();
        }
    }
}

extern "C" void kernel_gpu_cuda_wrapper_impl(par_str par_cpu,
                                             dim_str dim_cpu,
                                             box_str* box_cpu,
                                             FOUR_VECTOR* rv_cpu,
                                             fp* qv_cpu,
                                             FOUR_VECTOR* fv_cpu)
{
#ifdef TIMING
    struct timeval tv_total_start, tv_init_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0.0f, mem_alloc_time = 0.0f, h2d_time = 0.0f, kernel_time = 0.0f;
    float d2h_time = 0.0f, close_time = 0.0f, total_time = 0.0f;

    gettimeofday(&tv_total_start, NULL);
#endif

    int num_devices = 0;
    CUDA_CHECK(cudaGetDeviceCount(&num_devices));
    if (num_devices <= 0) {
        printf("Cuda error: no devices available.\n");
        fflush(NULL);
        exit(EXIT_FAILURE);
    }

    int device = 0;
#if defined(__GNUC__)
    if (&device_id_inuse) {
        device = device_id_inuse;
    }
#endif
    if (device < 0 || device >= num_devices) {
        device = 0;
    }

    CUDA_CHECK(cudaSetDevice(device));

    cudaDeviceProp prop;
    CUDA_CHECK(cudaGetDeviceProperties(&prop, device));

    printf("Platform: NVIDIA CUDA\n");
    printf("Device: %s\n", prop.name);

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    init_time = elapsed_ms(&tv_total_start, &tv_init_end);

    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    box_str* d_box_gpu = NULL;
    FOUR_VECTOR* d_rv_gpu = NULL;
    fp* d_qv_gpu = NULL;
    FOUR_VECTOR* d_fv_gpu = NULL;

    CUDA_CHECK(cudaMalloc((void**)&d_box_gpu, (size_t)dim_cpu.box_mem));
    CUDA_CHECK(cudaMalloc((void**)&d_rv_gpu, (size_t)dim_cpu.space_mem));
    CUDA_CHECK(cudaMalloc((void**)&d_qv_gpu, (size_t)dim_cpu.space_mem2));
    CUDA_CHECK(cudaMalloc((void**)&d_fv_gpu, (size_t)dim_cpu.space_mem));

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    mem_alloc_time = elapsed_ms(&tv_mem_alloc_start, &tv_mem_alloc_end);

    gettimeofday(&tv_h2d_start, NULL);
#endif

    CUDA_CHECK(cudaMemcpy(d_box_gpu, box_cpu, (size_t)dim_cpu.box_mem, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_rv_gpu, rv_cpu, (size_t)dim_cpu.space_mem, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_qv_gpu, qv_cpu, (size_t)dim_cpu.space_mem2, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_fv_gpu, fv_cpu, (size_t)dim_cpu.space_mem, cudaMemcpyHostToDevice));

#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    h2d_time = elapsed_ms(&tv_h2d_start, &tv_h2d_end);
#endif

    size_t local_work_size = NUMBER_THREADS;
    size_t global_work_size = (size_t)dim_cpu.number_boxes * local_work_size;

    printf("# of blocks = %lu, # of threads/block = %lu (ensure that device can handle)\n",
           (unsigned long)(global_work_size / local_work_size),
           (unsigned long)local_work_size);

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    kernel_gpu_cuda<<<(unsigned int)dim_cpu.number_boxes, NUMBER_THREADS>>>(
        par_cpu, dim_cpu, d_box_gpu, d_rv_gpu, d_qv_gpu, d_fv_gpu);
    CUDA_CHECK(cudaPeekAtLastError());
    CUDA_CHECK(cudaDeviceSynchronize());

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    kernel_time = elapsed_ms(&tv_kernel_start, &tv_kernel_end);

    gettimeofday(&tv_d2h_start, NULL);
#endif

    CUDA_CHECK(cudaMemcpy(fv_cpu, d_fv_gpu, (size_t)dim_cpu.space_mem, cudaMemcpyDeviceToHost));

#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    d2h_time = elapsed_ms(&tv_d2h_start, &tv_d2h_end);

    gettimeofday(&tv_close_start, NULL);
#endif

    CUDA_CHECK(cudaFree(d_rv_gpu));
    CUDA_CHECK(cudaFree(d_qv_gpu));
    CUDA_CHECK(cudaFree(d_fv_gpu));
    CUDA_CHECK(cudaFree(d_box_gpu));

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    close_time = elapsed_ms(&tv_close_start, &tv_close_end);
    total_time = elapsed_ms(&tv_total_start, &tv_close_end);

    printf("Time spent in different stages of the application:\n");
    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

